#!/usr/bin/env python3
from pathlib import Path
import itertools, zlib, lzma, gzip, io, string

path='/home/ctfplayer/ctf_files/chal/cell.pkg'
b=Path(path).read_bytes()
payload=b[0x140:]
needle=b'csaw_ctf{'
frags=[b'csaw',b'ctf{',b'{']
print(f'file_len={len(b)} payload_len={len(payload)}')

hits=[]

def add_hit(kind,params,data=None,idx=None,extra=''):
    rec=(kind,params,idx,extra)
    hits.append((rec,data))
    print('[HIT]',rec)
    if data is not None and idx is not None:
        s=max(0,idx-32); e=min(len(data),idx+96)
        sn=data[s:e]
        try:
            print(sn.decode('latin1','ignore'))
        except: print(sn)

# raw scans
for region_name,data,base in [('full',b,0),('payload',payload,0x140)]:
    for n in [needle]+frags:
        i=data.find(n)
        while i!=-1:
            add_hit('raw',f'{region_name}:{n!r}',data,i)
            i=data.find(n,i+1)

# score near-miss strings
alphabet=set((string.ascii_letters+string.digits+'{}_:-').encode())
def near_score(d):
    # find windows with many expected chars and containing c?aw_ctf
    best=[]
    target=b'csaw_ctf'
    for i in range(0,min(len(d)-16,200000),1):
        w=d[i:i+24]
        sc=sum(c in alphabet for c in w)
        if sc>18 and b'ctf' in w:
            best.append((sc,i,w))
    best.sort(reverse=True)
    return best[:5]

# transforms

def xor1(d,k): return bytes(x^k for x in d)
def addc(d,k): return bytes((x+k)&0xff for x in d)
def subc(d,k): return bytes((x-k)&0xff for x in d)
def rol(x,r): return ((x<<r)&0xff)|(x>>(8-r))
def ror(x,r): return (x>>r)|((x<<(8-r))&0xff)
def rolb(d,r): return bytes(rol(x,r) for x in d)
def rorb(d,r): return bytes(ror(x,r) for x in d)

def scan(name,d,params=''):
    i=d.find(needle)
    if i!=-1:
        add_hit(name,params,d,i)
    for n in frags:
        j=d.find(n)
        if j!=-1 and n!=b'{':
            add_hit(name+'_frag',f'{params} {n!r}',d,j)
    # MZ header + DOS stub hint
    mz=d.find(b'MZ')
    if mz!=-1:
        if b'This program cannot be run in DOS mode' in d[mz:mz+0x300]:
            add_hit(name+'_MZ',params,d,mz,'dosstub')

# single xor
for k in range(256):
    d=xor1(payload,k)
    scan('xor1',d,f'k={k:#x}')

# repeating xor keylen 2..8 using crib for 'csaw_ctf{'
L=len(needle)
for keylen in range(2,9):
    for pos in range(0,min(len(payload)-L,60000)):
        key=[None]*keylen
        ok=True
        for j,ch in enumerate(needle):
            idx=(pos+j)%keylen
            kv=payload[pos+j]^ch
            if key[idx] is None: key[idx]=kv
            elif key[idx]!=kv:
                ok=False; break
        if not ok: continue
        # fill unknowns printable guesses small set
        unk=[i for i,v in enumerate(key) if v is None]
        cand_keys=[]
        if not unk:
            cand_keys=[bytes(key)]
        else:
            # printable heuristic limited
            choices=[list(range(0x20,0x7f)) for _ in unk]
            for prod in itertools.islice(itertools.product(*choices),0,4000):
                k2=key[:]
                for ui,val in zip(unk,prod): k2[ui]=val
                cand_keys.append(bytes(k2))
        for k in cand_keys[:200]:
            d=bytes(payload[i]^k[i%keylen] for i in range(len(payload)))
            if needle in d:
                scan('xorrep',d,f'keylen={keylen} key={k.hex()} pos={pos}')
                break

# add/sub shifts
for k in range(256):
    scan('add',addc(payload,k),f'k={k}')
    scan('sub',subc(payload,k),f'k={k}')

# bit rotations with/without xor
for r in range(1,8):
    d1=rolb(payload,r); d2=rorb(payload,r)
    scan('rol',d1,f'r={r}')
    scan('ror',d2,f'r={r}')
    for k in range(256):
        scan('rol_xor',xor1(d1,k),f'r={r} k={k}')
        scan('ror_xor',xor1(d2,k),f'r={r} k={k}')

# index-based streams
N=len(payload)
idx=bytes([i&0xff for i in range(N)])
scan('xor_idx',bytes(payload[i]^ (i&0xff) for i in range(N)),'b^i')
scan('xor_notidx',bytes(payload[i]^ ((~i)&0xff) for i in range(N)),'b^~i')
scan('add_idx',bytes((payload[i]+(i&0xff))&0xff for i in range(N)),'b+i')
scan('sub_idx',bytes((payload[i]-(i&0xff))&0xff for i in range(N)),'b-i')
scan('xor_i_mul3',bytes(payload[i]^((i*3)&0xff) for i in range(N)),'b^(3i)')
scan('xor_i_mul7',bytes(payload[i]^((i*7)&0xff) for i in range(N)),'b^(7i)')

# compression attempts after candidate transforms (headers)
transforms=[]
transforms.append(('raw',payload))
for k in range(256):
    transforms.append((f'xor{k}',xor1(payload,k)))
    transforms.append((f'add{k}',addc(payload,k)))
    transforms.append((f'sub{k}',subc(payload,k)))

for name,d in transforms:
    # zlib headers common 78 01/5e/9c/da
    for off in range(0,min(len(d)-2,2000)):
        if d[off]==0x78 and d[off+1] in (0x01,0x5e,0x9c,0xda):
            try:
                out=zlib.decompress(d[off:])
                if needle in out:
                    add_hit('zlib',f'{name} off={off}',out,out.find(needle))
            except: pass
        if d[off:off+2]==b'\x1f\x8b':
            try:
                out=gzip.decompress(d[off:])
                if needle in out:
                    add_hit('gzip',f'{name} off={off}',out,out.find(needle))
            except: pass
    # lzma magic
    for mg in [b'\xfd7zXZ\x00']:
        off=d.find(mg)
        if off!=-1:
            try:
                out=lzma.decompress(d[off:])
                if needle in out:
                    add_hit('lzma',f'{name} off={off}',out,out.find(needle))
            except: pass

print('total hits',len(hits))
# top near misses sample from a few transforms
samples=[('raw',payload),('xor0x20',xor1(payload,0x20)),('sub1',subc(payload,1)),('add1',addc(payload,1)),('xor_idx',bytes(payload[i]^(i&0xff) for i in range(len(payload))))]
for n,d in samples:
    nm=near_score(d)
    if nm:
        print('near',n,nm[:2])

